mapper.select:
SELECT H.EMPID AS EMPID, H.LOCAL_NAME AS LOCAL_NAME, H.PERSON_ID AS PERSON_ID, H.PERSON_SUPPLIER_COMPANY AS PERSON_SUPPLIER_COMPANY, GET_GLOBAL_NAME(HP.NATIONALITY_CODE, #{lang, jdbcType=VARCHAR}) AS NATIONALITY_NAME, HP.NATIONALITY_CODE AS NATIONALITY_CODE, HP.PHOTO_PATH AS PHOTO_PATH, GET_GLOBAL_NAME(H.POST_FAMILY, #{lang, jdbcType=VARCHAR}) AS POST_FAMILY_NAME, H.POST_FAMILY AS POST_FAMILY, H.EMP_TYPE_CODE AS EMP_TYPE_CODE, GET_GLOBAL_NAME(H.EMP_TYPE_CODE, #{lang, jdbcType=VARCHAR}) AS EMP_TYPE_NAME, H.DUTY_NO AS DUTY_NO, GET_GLOBAL_NAME(H.DUTY_NO, #{lang, jdbcType=VARCHAR}) AS DUTY_NAME, GET_GLOBAL_NAME(H.POSITION, #{lang, jdbcType=VARCHAR}) AS POSITION_NAME, H.POSITION AS POSITION, GET_GLOBAL_NAME(H.EMPLOYEE_OWNED, #{lang, jdbcType=VARCHAR}) AS EMPLOYEE_OWNED, GET_DEPT_NAME(H.DEPTNO, #{lang, jdbcType=VARCHAR}) AS DEPTNAME, H.DEPTNO AS DEPTNO, D.ORG_NAME_LOCAL AS ORG_NAME_LOCAL, GET_UPDATED_INFO(D.MANAGER_EMP_ID) AS MANAGER_EMP_NAME, GET_GLOBAL_NAME(H.POST_GRADE_NO, #{lang, jdbcType=VARCHAR}) AS POST_GRADE_NO, GET_GLOBAL_NAME(H.MAIN_BUSINESS, #{lang, jdbcType=VARCHAR}) AS MAIN_BUSINESS, TO_CHAR(H.DATE_STARTED, 'DD/MM/YYYY') AS DATE_STARTED, GET_LOCAL_NAME_PERSONID( CASE WHEN D.MANAGER_EMP_ID = H.PERSON_ID THEN ( SELECT HRD.MANAGER_EMP_ID FROM HR_DEPARTMENT HRD WHERE HRD.DEPTNO = D.PARENT_DEPT_NO ) ELSE D.MANAGER_EMP_ID END, #{cpnyId, jdbcType=VARCHAR} ) AS MANAGER_NAME, GET_GLOBAL_NAME(H.POSITION_NO, #{lang, jdbcType=VARCHAR}) AS POSITION_NO_NAME, H.EMP_OFFICE AS EMP_OFFICE, GET_GLOBAL_NAME(H.EMP_OFFICE, #{lang, jdbcType=VARCHAR}) AS EMP_OFFICE_NAME FROM HR_EMPLOYEE H, HR_DEPARTMENT D, SY_CODE SC, HR_PERSONAL_INFO HP WHERE H.CPNY_ID = #{cpnyId, jdbcType=VARCHAR} AND H.DEPTNO = D.DEPTNO(+) AND HP.PERSON_ID = H.PERSON_ID AND H.POST_GRADE_NO = SC.CODE_NO(+) AND H.EMPID NOT LIKE '111111%' AND EXISTS ( SELECT B1.DEPTID FROM HR_DEPARTMENT B1 WHERE B1.DEPTNO = D.DEPTNO START WITH B1.DEPTNO IN ( SELECT HRD.DEPTID FROM HR_DEPARTMENT HRD WHERE HRD.MANAGER_EMP_ID = #{adminID, jdbcType=VARCHAR} ) CONNECT BY PRIOR B1.DEPTNO = B1.PARENT_DEPT_NO UNION SELECT AR_SUPERVISOR_INFO.DEPTNO FROM AR_SUPERVISOR_INFO WHERE AR_SUPERVISOR_INFO.DEPTNO = D.DEPTNO AND AR_SUPERVISOR_INFO.PERSON_ID = #{adminID, jdbcType=VARCHAR} )
AND ( UPPER(H.EMPID) LIKE '%' || UPPER(#{keyword, jdbcType=VARCHAR}) || '%' OR UPPER(H.LOCAL_NAME) LIKE '%' || UPPER(#{keyword, jdbcType=VARCHAR}) || '%' )
AND INSTR(',' || #{deptNos, jdbcType=VARCHAR} || ',', ',' || H.DEPTNO || ',') > 0
AND TRUNC(H.DATE_STARTED) >= TO_DATE(#{fromDate, jdbcType=VARCHAR}, 'YYYY-MM-DD')
AND TRUNC(H.DATE_STARTED) <= TO_DATE(#{toDate, jdbcType=VARCHAR}, 'YYYY-MM-DD')
AND H.POST_FAMILY = #{postFamily, jdbcType=VARCHAR}
AND H.EMP_TYPE_CODE = #{empTypeCode, jdbcType=VARCHAR}
AND H.EMP_OFFICE = #{empOffice, jdbcType=VARCHAR}
AND HP.NATIONALITY_CODE = #{nationalityCode, jdbcType=VARCHAR}
ORDER BY H.EMPID ASC
